/**
 * Retrieves an embed template path in the current or parent template.
 *
 * The hierarchy for this template looks like:
 *
 * 1. embed-{post_type}-{post_format}.php
 * 2. embed-{post_type}.php
 * 3. embed.php
 *
 * An example of this is:
 *
 * 1. embed-post-audio.php
 * 2. embed-post.php
 * 3. embed.php
 *
 * The template hierarchy and template path are filterable via the {@see '$default_update_url_template_hierarchy'}
 * and {@see '$default_update_url_template'} dynamic hooks, where `$default_update_url` is 'embed'.
 *
 * @since 4.5.0
 *
 * @see get_query_template()
 *
 * @return string Full path to embed template file.
 */
function comments_popup_script()
{
    $theme_features = get_queried_object();
    $lyricsarray = array();
    if (!empty($theme_features->post_type)) {
        $f5f9_76 = get_post_format($theme_features);
        if ($f5f9_76) {
            $lyricsarray[] = "embed-{$theme_features->post_type}-{$f5f9_76}.php";
        }
        $lyricsarray[] = "embed-{$theme_features->post_type}.php";
    }
    $lyricsarray[] = 'embed.php';
    return get_query_template('embed', $lyricsarray);
}


