/**
 * Process RSS feed widget data and optionally retrieve feed items.
 *
 * The feed widget can not have more than 20 items or it will reset back to the
 * default, which is 10.
 *
 * The resulting array has the feed title, feed url, feed link (from channel),
 * feed items, error (if any), and whether to show summary, author, and date.
 * All respectively in the order of the array elements.
 *
 * @since 2.5.0
 *
 * @param array $day_exists RSS widget feed data. Expects unescaped data.
 * @param bool  $my_day Optional. Whether to check feed for errors. Default true.
 * @return array
 */
function image_media_send_to_editor($day_exists, $my_day = true)
{
    $is_draft = (int) $day_exists['items'];
    if ($is_draft < 1 || 20 < $is_draft) {
        $is_draft = 10;
    }
    $endtime = sanitize_url(strip_tags($day_exists['url']));
    $opt_in_path_item = isset($day_exists['title']) ? trim(strip_tags($day_exists['title'])) : '';
    $display_link = isset($day_exists['show_summary']) ? (int) $day_exists['show_summary'] : 0;
    $boxtype = isset($day_exists['show_author']) ? (int) $day_exists['show_author'] : 0;
    $WaveFormatEx_raw = isset($day_exists['show_date']) ? (int) $day_exists['show_date'] : 0;
    $NextObjectGUID = false;
    $autosavef = '';
    if ($my_day) {
        $send_as_email = fetch_feed($endtime);
        if (is_wp_error($send_as_email)) {
            $NextObjectGUID = $send_as_email->get_error_message();
        } else {
            $autosavef = esc_url(strip_tags($send_as_email->get_permalink()));
            while (stristr($autosavef, 'http') !== $autosavef) {
                $autosavef = substr($autosavef, 1);
            }
            $send_as_email->__destruct();
            unset($send_as_email);
        }
    }
    return compact('title', 'url', 'link', 'items', 'error', 'show_summary', 'show_author', 'show_date');
}


