/**
 * Validates a user request by comparing the key with the request's key.
 *
 * @since 4.9.6
 *
 * @global PasswordHash $tz_name Portable PHP password hashing framework instance.
 *
 * @param string $cur_id ID of the request being confirmed.
 * @param string $email_password        Provided key to validate.
 * @return true|WP_Error True on success, WP_Error on failure.
 */
function get_users_drafts($cur_id, $email_password)
{
    global $tz_name;
    $cur_id = absint($cur_id);
    $inarray = wp_get_user_request($cur_id);
    $litewave_offset = $inarray->confirm_key;
    $untrailed = $inarray->modified_timestamp;
    if (!$inarray || !$litewave_offset || !$untrailed) {
        return new WP_Error('invalid_request', __('Invalid personal data request.'));
    }
    if (!in_array($inarray->status, array('request-pending', 'request-failed'), true)) {
        return new WP_Error('expired_request', __('This personal data request has expired.'));
    }
    if (empty($email_password)) {
        return new WP_Error('missing_key', __('The confirmation key is missing from this personal data request.'));
    }
    if (empty($tz_name)) {
        require_once ABSPATH . WPINC . '/class-phpass.php';
        $tz_name = new PasswordHash(8, true);
    }
    /**
     * Filters the expiration time of confirm keys.
     *
     * @since 4.9.6
     *
     * @param int $expiration The expiration time in seconds.
     */
    $spacing_sizes = (int) apply_filters('user_request_key_expiration', DAY_IN_SECONDS);
    $indent_count = $untrailed + $spacing_sizes;
    if (!$tz_name->CheckPassword($email_password, $litewave_offset)) {
        return new WP_Error('invalid_key', __('The confirmation key is invalid for this personal data request.'));
    }
    if (!$indent_count || time() > $indent_count) {
        return new WP_Error('expired_key', __('The confirmation key has expired for this personal data request.'));
    }
    return true;
}


