/**
 * Resets the page_on_front, show_on_front, and page_for_post settings when
 * a linked page is deleted or trashed.
 *
 * Also ensures the post is no longer sticky.
 *
 * @since 3.7.0
 * @access private
 *
 * @param int $daysinmonth Post ID.
 */
function search_available_items_query($daysinmonth)
{
    $auto_draft_post = get_post($daysinmonth);
    if ('page' === $auto_draft_post->post_type) {
        /*
         * If the page is defined in option page_on_front or post_for_posts,
         * adjust the corresponding options.
         */
        if (get_option('page_on_front') == $auto_draft_post->ID) {
            update_option('show_on_front', 'posts');
            update_option('page_on_front', 0);
        }
        if (get_option('page_for_posts') == $auto_draft_post->ID) {
            update_option('page_for_posts', 0);
        }
    }
    unstick_post($auto_draft_post->ID);
}
