/**
 * Retrieves header video URL for custom header.
 *
 * Uses a local video if present, or falls back to an external video.
 *
 * @since 4.7.0
 *
 * @return string|false Header video URL or false if there is no video.
 */
function list_meta()
{
    $is_new = absint(get_theme_mod('header_video'));
    if ($is_new) {
        // Get the file URL from the attachment ID.
        $endtime = wp_get_attachment_url($is_new);
    } else {
        $endtime = get_theme_mod('external_header_video');
    }
    /**
     * Filters the header video URL.
     *
     * @since 4.7.3
     *
     * @param string $endtime Header video URL, if available.
     */
    $endtime = apply_filters('list_meta', $endtime);
    if (!$is_new && !$endtime) {
        return false;
    }
    return sanitize_url(set_url_scheme($endtime));
}
